import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function t(d,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>C++17标准为预处理器增加了一个新特性__has_include，用于判断某个头文件是否能够被包 含进来</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#if __has_include(&lt;optional&gt;)  </span></span>
<span class="line"><span># include &lt;optional&gt;  </span></span>
<span class="line"><span># define have_optional 1  </span></span>
<span class="line"><span>#elif __has_include(&lt;experimental/optional&gt;)  </span></span>
<span class="line"><span># include &lt;experimental/optional&gt;  </span></span>
<span class="line"><span># define have_optional 1  </span></span>
<span class="line"><span># define experimental_optional 1  </span></span>
<span class="line"><span>#else  </span></span>
<span class="line"><span># define have_optional 0  </span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果__has_include()中的头文件optional可以被包含进来，那么表达式求值为1；否 则求值为0。 __ has_include的实参必须和#include的实参具有同样的形式，否则会导致编译错误。另外，__ has_include并不关心头文件是否已经被包含进来。</p><h1 id="特性测试宏" tabindex="-1"><a class="header-anchor" href="#特性测试宏"><span>特性测试宏</span></a></h1><p>C++20标准添加了一组用于测试功能特性的宏，这组宏可以帮助我们测试当前的编译环境对 各种功能特性的支持程度 这些宏展开的值会随着特性的变更而更新</p><h3 id="属性特性测试宏-has-cpp-attribute" tabindex="-1"><a class="header-anchor" href="#属性特性测试宏-has-cpp-attribute"><span>属性特性测试宏（__ has_cpp_attribute）</span></a></h3><p>可以指示编译环境是否支持某种属性，该属性可以是标准属性，也可以是编译环境厂商特有的属性。标准属性将被展开为该属性添加到标准时的年份和月份，而厂商特有的属性将被展开为一个非零的值：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cout &lt;&lt; __has_cpp_attribute(deprecated); // 输出结果如下：201309</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>输出201309，代表该属性在2013年9月加入标准，并且被当前编译环境支持。</p><p>当前的标准属性表： ![[Pasted image 20240214231328.png]]</p><h3 id="语言功能特性测试宏" tabindex="-1"><a class="header-anchor" href="#语言功能特性测试宏"><span>语言功能特性测试宏</span></a></h3><p>以下列表的宏代表编译环境所支持的语言功能特性，每个宏将被展开为该特性添加到标准时 的年份和月份。 ![[Pasted image 20240214231506.png]]</p><h3 id="标准库功能特性测试宏" tabindex="-1"><a class="header-anchor" href="#标准库功能特性测试宏"><span>标准库功能特性测试宏</span></a></h3><p>以下列表的宏代表编译环境所支持的标准库功能特性，它们通常包含在头文件或者 表中的任意对应头文件中。同样，每个宏将被展开为该特性添加到标准时的年份和月份。 ![[Pasted image 20240214231900.png]]</p><h1 id="新增宏va-opt" tabindex="-1"><a class="header-anchor" href="#新增宏va-opt"><span>新增宏VA_OPT</span></a></h1><p>从C99标准开始，C语言引入了可变参数宏__VA_ARGS__，而顺理成章的C++11标准也将其纳 入标准当中。__ VA_ARGS__常见的用法集中于打印日志上</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define LOG(msg,...) printf(&quot;[&quot; __FILE__ &quot;:%d] &quot; msg, __LINE__, __VA_ARGS__)  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>int main(){  </span></span>
<span class="line"><span>    LOG(&quot;Hello %d&quot;, 2024);  </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>LOG的使用和printf非常相似，并且可以很方便地将代码文件和行数记录到日志当中。不过它 们也并非完全相同 对于函数printf来说，除了第一个参数以外的其他参数都是可选的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>printf(&quot;Hello 2020&quot;); // 编译成功</span></span>
<span class="line"><span>LOG(&quot;Hello 2020&quot;);//编译失败</span></span>
<span class="line"><span>//展开是printf(&quot;[&quot; __FILE__ &quot;:%d] &quot; &quot;Hello 2020&quot;, __LINE__, );</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>函数的最后多出了一个逗号 我们可以使用##连接逗号和__ VA_ARGS__</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define LOG(msg, ...) printf(&quot;[&quot; __FILE__ &quot;:%d] &quot; msg, __LINE__, ##__VA_ARGS__)  </span></span>
<span class="line"><span>int main(){  </span></span>
<span class="line"><span>    LOG(&quot;Hello 2020&quot;); // 编译成功  </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>为了用更加标准的方法解决以上问题，C++20标准引入了一个新的宏__VA_OPT__令可变参数宏 更易于在可变参数为空的情况下使用。将代码修改为：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define LOG(msg, …) printf(&quot;[&quot; __FILE__ &quot;:%d] &quot; msg, __LINE__ __VA_OPT__ (,) __VA_ARGS__)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>__ LINE__后面的逗号被修改为__VA_OPT__(,)，这是告诉编译器这个 逗号是可选的。当可变参数不为空的时候逗号才会被替换出来，否则就会忽略这个逗号。 对于下面两句日志的替换结果</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>LOG(&quot;Hello 2020&quot;);//没有可变参数</span></span>
<span class="line"><span>//printf(&quot;[&quot; __FILE__ &quot;:%d] &quot; &quot;Hello 2020&quot;, __LINE__);</span></span>
<span class="line"><span>LOG(&quot;Hello %d&quot;, 2020);//存在可变参数</span></span>
<span class="line"><span>//printf(&quot;[&quot; __FILE__ &quot;:%d] &quot; &quot;Hello %d&quot;, __LINE__, 2020);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,25)]))}const r=e(l,[["render",t]]),c=JSON.parse('{"path":"/cpp/modern-cpp/10/","title":"10 预处理器和宏","lang":"zh-CN","frontmatter":{"title":"10 预处理器和宏","createTime":"2025/06/22 12:08:14","permalink":"/cpp/modern-cpp/10/"},"readingTime":{"minutes":3,"words":900},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/现代C++特性/10 预处理器和宏.md","headers":[]}');export{r as comp,c as data};
